customMethods.script:
itemId = self.view.params.value or 0
methods = ["ByCount", "ByWeight", "ByVision"]
def _s(v):
	return "" if v is None else (v if isinstance(v, basestring) else unicode(v))
rows = []
if itemId:
	rows = BlueRidge.Parts.ContainerConfig.getByItemAll(itemId) or []
byMethod = {}
for r in rows:
	m = r.get("ClosureMethod")
	if m:
		byMethod[m] = r
def _build():
	out = {}
	for m in methods:
		r = byMethod.get(m)
		if r:
			out[m] = {
				"Id":                r.get("Id"),
				"ItemId":            itemId,
				"ClosureMethod":     m,
				"Active":            True,
				"PartsPerTray":      _s(r.get("PartsPerTray")),
				"TraysPerContainer": _s(r.get("TraysPerContainer")),
				"DunnageCode":       _s(r.get("DunnageCode")),
				"CustomerCode":      _s(r.get("CustomerCode")),
				"IsSerialized":      bool(r.get("IsSerialized", False)),
				"TargetWeight":      _s(r.get("TargetWeight")),
			}
		else:
			out[m] = {
				"Id": None, "ItemId": itemId, "ClosureMethod": m,
				"Active": False,
				"PartsPerTray": "", "TraysPerContainer": "",
				"DunnageCode": "", "CustomerCode": "",
				"IsSerialized": False, "TargetWeight": "",
			}
	return out
self.view.custom.state = {"selected": _build(), "editDraft": _build()}

itemId = self.view.params.value or 0
if not itemId:
	BlueRidge.Common.Notify.toast("No item selected", "Select an item before saving container configuration.", "warning")
	return
draft = system.util.jsonDecode(BlueRidge.Common.Util.convertWrapperObjectToJson(self.view.custom.state.editDraft)) or {}
methods = ["ByCount", "ByWeight", "ByVision"]
def _toNum(v):
	if v is None or v == "":
		return None
	try:
		return int(v)
	except (ValueError, TypeError):
		try:
			return float(v)
		except (ValueError, TypeError):
			return None
toSave = []
toDeprecate = []
for m in methods:
	block = draft.get(m) or {}
	priorId = block.get("Id")
	partsPerTray = _toNum(block.get("PartsPerTray"))
	if partsPerTray is not None and partsPerTray > 0:
		trays = _toNum(block.get("TraysPerContainer"))
		if trays is None or trays <= 0:
			BlueRidge.Common.Notify.toast("Trays per Container required", "Enter a positive trays per container for the %s pack-out." % m, "warning")
			return
		targetWeight = None
		if m == "ByWeight":
			targetWeight = _toNum(block.get("TargetWeight"))
			if targetWeight is None or targetWeight <= 0:
				BlueRidge.Common.Notify.toast("Target Weight required", "The By Weight pack-out requires a positive target weight.", "warning")
				return
		toSave.append({"Id": priorId, "ItemId": itemId, "ClosureMethod": m, "TraysPerContainer": trays, "PartsPerTray": partsPerTray, "TargetWeight": targetWeight, "DunnageCode": block.get("DunnageCode"), "CustomerCode": block.get("CustomerCode"), "IsSerialized": bool(block.get("IsSerialized", False))})
	elif priorId:
		toDeprecate.append({"Id": priorId, "ClosureMethod": m})
if not toSave and not toDeprecate:
	BlueRidge.Common.Notify.toast("Nothing to save", "Add at least one pack-out, or leave it cleared.", "info")
	return
failures = []
for payload in toSave:
	if payload.get("Id"):
		result = BlueRidge.Parts.ContainerConfig.update(payload)
	else:
		result = BlueRidge.Parts.ContainerConfig.add(payload)
	if not (result and result.get("Status")):
		msg = (result or {}).get("Message") or "Unknown error"
		failures.append("%s - %s" % (payload["ClosureMethod"], msg))
for dep in toDeprecate:
	result = BlueRidge.Parts.ContainerConfig.deprecate(dep["Id"])
	if not (result and result.get("Status")):
		msg = (result or {}).get("Message") or "Unknown error"
		failures.append("%s - %s" % (dep["ClosureMethod"], msg))
if failures:
	BlueRidge.Common.Notify.toast("Some pack-outs not saved", "; ".join(failures), "error")
else:
	BlueRidge.Common.Notify.toast("Container config saved", "Pack-out configuration saved.", "success")
self.load()

draft = system.util.jsonDecode(BlueRidge.Common.Util.convertWrapperObjectToJson(self.view.custom.state.editDraft)) or {}
block = draft.get(method) or {}
block["Active"] = True
if block.get("ClosureMethod") is None:
	block["ClosureMethod"] = method
if block.get("ItemId") is None:
	block["ItemId"] = self.view.params.value or 0
draft[method] = block
self.view.custom.state.editDraft = draft

st = system.util.jsonDecode(BlueRidge.Common.Util.convertWrapperObjectToJson(self.view.custom.state)) or {}
sel = st.get("selected") or {}
draft = st.get("editDraft") or {}
cur = draft.get(method) or {}
draft[method] = {"Id": cur.get("Id"), "ItemId": self.view.params.value or 0, "ClosureMethod": method, "Active": False, "PartsPerTray": "", "TraysPerContainer": "", "DunnageCode": "", "CustomerCode": "", "IsSerialized": False, "TargetWeight": ""}
self.view.custom.state = {"selected": sel, "editDraft": draft}
